import{_ as t}from"./chunks/微笑狼的公开仓库.gGdYP2E_.js";import{_ as e,o as i,c as s,a2 as o}from"./chunks/framework.DnrXFDHb.js";const m=JSON.parse('{"title":"Auto Tagging","description":"","frontmatter":{},"headers":[],"relativePath":"my/Other/auto-tagging.md","filePath":"my/Other/auto-tagging.md","lastUpdated":1781962217000}'),n={name:"my/Other/auto-tagging.md"};function d(l,a,g,c,r,p){return i(),s("div",null,[...a[0]||(a[0]=[o('<h1 id="auto-tagging" tabindex="-1">Auto Tagging <a class="header-anchor" href="#auto-tagging" aria-label="Permalink to &quot;Auto Tagging&quot;">​</a></h1><p>Auto tagging ကို ဒီနေရာမှာ configure လုပ်နိုင်ပါတယ်:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Other Settings -&gt; Auto Tagging</span></span></code></pre></div><p>ဒီ feature က image tags တွေကိုအလိုအလျောက်ဖန်တီးပေးပါတယ်။ အဲဒီ tags တွေက search, random image filtering, public gallery filtering, age-rating access control တို့အတွက်အသုံးဝင်ပါတယ်။</p><h2 id="auto-tagging-က-ဘာတွေလုပ်နိုင်လဲ" tabindex="-1">Auto Tagging က ဘာတွေလုပ်နိုင်လဲ <a class="header-anchor" href="#auto-tagging-က-ဘာတွေလုပ်နိုင်လဲ" aria-label="Permalink to &quot;Auto Tagging က ဘာတွေလုပ်နိုင်လဲ&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Feature</th><th>Description</th></tr></thead><tbody><tr><td>content tags ဖန်တီးခြင်း</td><td>people, scenes, objects, art style နဲ့ အလားတူ visual content အတွက် tags ထည့်ပေးသည်။</td></tr><tr><td>character tags ဖန်တီးခြင်း</td><td>anime images နဲ့ illustrations အတွက်အသုံးဝင်သည်။</td></tr><tr><td>orientation tags ထည့်ခြင်း</td><td><code>landscape</code>, <code>portrait</code>, <code>square</code> ကိုထည့်ပေးသည်။</td></tr><tr><td>image rating ထည့်ခြင်း</td><td>general, sensitive, questionable, explicit content အတွက် <code>G/S/Q/E</code> rating results သိမ်းသည်။</td></tr><tr><td>upload မှာ auto-tag</td><td>newly uploaded images တွေက tagging flow ထဲအလိုအလျောက်ဝင်သည်။</td></tr><tr><td>Batch tagging</td><td>folders အားလုံး သို့မဟုတ် selected folders ထဲက images အဟောင်းတွေကို tags ထည့်သည်။</td></tr></tbody></table><h2 id="အရင်ပြင်ဆင်ရမယ့်အရာ" tabindex="-1">အရင်ပြင်ဆင်ရမယ့်အရာ <a class="header-anchor" href="#အရင်ပြင်ဆင်ရမယ့်အရာ" aria-label="Permalink to &quot;အရင်ပြင်ဆင်ရမယ့်အရာ&quot;">​</a></h2><p>အနည်းဆုံး accessible Hugging Face Space URL တစ်ခုပြင်ဆင်ပါ။</p><p>အကြံပြုတဲ့နည်းက SmilingWolf ရဲ့ <code>wd-tagger</code> Space ကို ကိုယ့် Hugging Face account ထဲ duplicate လုပ်ခြင်းဖြစ်ပါတယ်:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://huggingface.co/spaces/SmilingWolf/wd-tagger</span></span></code></pre></div><p>public Space ကို temporary testing အတွက်သုံးနိုင်ပေမယ့် public Spaces တွေကို users အများကြီး share သုံးပါတယ်။ queue ရှိနိုင်၊ နှေးနိုင်၊ မရနိုင်တဲ့အချိန်ရှိနိုင်ပါတယ်။ ကိုယ်ပိုင် account ထဲ duplicated Space က long-term auto tagging အတွက်ပိုတည်ငြိမ်ပါတယ်။</p><h2 id="smilingwolf-space-duplicate-လုပ်ပါ" tabindex="-1">SmilingWolf Space Duplicate လုပ်ပါ <a class="header-anchor" href="#smilingwolf-space-duplicate-လုပ်ပါ" aria-label="Permalink to &quot;SmilingWolf Space Duplicate လုပ်ပါ&quot;">​</a></h2><ol><li>Hugging Face ထဲ sign in ဝင်ပါ။</li><li><code>https://huggingface.co/spaces/SmilingWolf/wd-tagger</code> ကိုဖွင့်ပါ။</li></ol><p><img src="'+t+`" alt="SmilingWolf public Space" loading="lazy"></p><ol start="3"><li>ညာဘက်အပေါ်ထောင့်က three-dot menu ကိုနှိပ်ပါ။</li><li><code>Duplicate this Space</code> ကိုရွေးပါ။</li><li>default Space name ကိုထားနိုင်သလို <code>wd-tagger</code> စတဲ့အမည်လည်းပေးနိုင်ပါတယ်။</li><li>visibility ကို <code>Public</code> ထားပါ။ Public Spaces တွေကို ImgBed က call လုပ်ရပိုလွယ်ပါတယ်။</li><li>စစချင်း default free hardware ကိုထားပါ။ queue ကပြဿနာဖြစ်လာမှ upgrade လုပ်ပါ။</li><li>Space ကို create လုပ်ပြီး build ပြီးအောင်စောင့်ပါ။</li></ol><p>build ပြီးရင် သင့် Space page ကိုဖွင့်ပါ။ URL က များသောအားဖြင့်ဒီလိုဖြစ်ပါတယ်:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://huggingface.co/spaces/your-name/wd-tagger</span></span></code></pre></div><p>browser URL ကို copy လုပ်ပြီး ImgBed ထဲက <code>Space URLs</code> မှာ paste လုပ်ပါ။</p><h2 id="space-url-အများကြီးထည့်ခြင်း" tabindex="-1">Space URL အများကြီးထည့်ခြင်း <a class="header-anchor" href="#space-url-အများကြီးထည့်ခြင်း" aria-label="Permalink to &quot;Space URL အများကြီးထည့်ခြင်း&quot;">​</a></h2><p>line တစ်ကြောင်းမှာ Space URL တစ်ခုစီထည့်ပါ။</p><table tabindex="0"><thead><tr><th>Value</th><th>Description</th></tr></thead><tbody><tr><td><code>https://huggingface.co/spaces/SmilingWolf/wd-tagger</code></td><td>SmilingWolf public Space။ temporary testing အတွက်သင့်တော်သည်။</td></tr><tr><td><code>https://huggingface.co/spaces/lintonxue00/wd-tagger</code></td><td>copy လုပ်ထားတဲ့ Space page URL။</td></tr><tr><td><code>https://huggingface.co/spaces/your-name/wd-tagger</code></td><td>သင့်ကိုယ်ပိုင် duplicated Space page URL။</td></tr></tbody></table><p>URLs အများကြီးထည့်နိုင်ပါတယ်။ ImgBed က Spaces အများကြီးကိုအတူသုံးပြီး speed ပိုကောင်းနိုင်ပါတယ်။</p><p>Space တစ်ခု temporary unavailable ဖြစ်လည်း အခြား Spaces တွေက processing ဆက်လုပ်နိုင်ပါတယ်။</p><h2 id="settings" tabindex="-1">Settings <a class="header-anchor" href="#settings" aria-label="Permalink to &quot;Settings&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Option</th><th>Recommendation</th></tr></thead><tbody><tr><td><code>Space URLs</code></td><td>ပြင်ဆင်ထားတဲ့ Space URLs ထည့်ပါ။ အနည်းဆုံးတစ်ခုလိုပါတယ်။</td></tr><tr><td>Target folder</td><td>folders အားလုံးအတွက် ဗလာထားပါ။ specific directory ကို process လုပ်ချင်မှသာ folder ရွေးပါ။</td></tr><tr><td>Recognition model</td><td>default <code>wd-swinv2-tagger-v3</code> ကိုထားပါ။</td></tr><tr><td>General tag threshold</td><td>default က images အများစုအတွက်သင့်တော်ပါတယ်။ တန်ဖိုးနည်းလျှင် tags ပိုများ၊ တန်ဖိုးမြင့်လျှင် tags ပိုနည်းသည်။</td></tr><tr><td>Character tag threshold</td><td>default က conservative ဖြစ်ပြီးမှားယွင်းတဲ့ character tags လျော့စေသည်။</td></tr><tr><td><code>MCut</code> automatic threshold</td><td>စစချင်း off ထားပါ။ model က tag count ကိုအလိုအလျောက်ဆုံးဖြတ်စေချင်ရင် on လုပ်ပါ။</td></tr><tr><td>Auto-tag on upload</td><td>newly uploaded images တွေကို auto tag ပေးချင်လျှင် on လုပ်ပါ။</td></tr><tr><td>Start tagging</td><td>images အဟောင်းတွေအတွက် manual batch-tagging စတင်သည်။</td></tr></tbody></table><h2 id="အကြံပြု-starting-values" tabindex="-1">အကြံပြု Starting Values <a class="header-anchor" href="#အကြံပြု-starting-values" aria-label="Permalink to &quot;အကြံပြု Starting Values&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Option</th><th>Recommended Value</th></tr></thead><tbody><tr><td>Recognition model</td><td><code>wd-swinv2-tagger-v3</code></td></tr><tr><td>General tag threshold</td><td><code>0.35</code></td></tr><tr><td>Character tag threshold</td><td><code>0.85</code></td></tr><tr><td><code>MCut</code></td><td>စစချင်း Off</td></tr><tr><td>Auto-tag on upload</td><td>လိုအပ်လျှင် Enable</td></tr></tbody></table><p>tags များလွန်းရင် general threshold ကိုအနည်းငယ်မြှင့်ပါ။</p><p>tags နည်းလွန်းရင် general threshold ကိုအနည်းငယ်လျှော့ပါ။</p><h2 id="batch-tagging" tabindex="-1">Batch Tagging <a class="header-anchor" href="#batch-tagging" aria-label="Permalink to &quot;Batch Tagging&quot;">​</a></h2><ol><li><code>Space URLs</code> ဖြည့်ပါ။</li><li>target folder ရွေးပါ။</li><li>start tagging ကိုနှိပ်ပါ။</li><li>progress ပြီးအောင်စောင့်ပါ။</li></ol><p>target folder ဗလာဖြစ်လျှင် ImgBed က folders အားလုံးကို process လုပ်ပါမယ်။</p><p>Batch tagging က images အဟောင်းတွေအတွက်အကောင်းဆုံးပါ။ images အသစ်တွေအတွက် auto-tag on upload ကို enable လုပ်ထားရင် တစ်ခါတစ်ခါ manual run မလိုတော့ပါ။</p><h2 id="upload-အချိန်-auto-tag" tabindex="-1">Upload အချိန် Auto-Tag <a class="header-anchor" href="#upload-အချိန်-auto-tag" aria-label="Permalink to &quot;Upload အချိန် Auto-Tag&quot;">​</a></h2><p>auto-tag on upload enabled ဖြစ်ပြီးနောက် newly uploaded images တွေက configured <code>Space URLs</code> ကိုအလိုအလျောက် call လုပ်ပါမယ်။</p><p>ဒီဟာက long-term use အတွက်သင့်တော်ပါတယ်။</p><p>Space queue ရှိနေရင် upload ကိုအရင် finish လုပ်နိုင်ပြီး tagging ကနောက်မှာဆက်လုပ်ပါမယ်။</p><h2 id="ဘယ်-images-တွေ-process-လုပ်လဲ" tabindex="-1">ဘယ် Images တွေ Process လုပ်လဲ <a class="header-anchor" href="#ဘယ်-images-တွေ-process-လုပ်လဲ" aria-label="Permalink to &quot;ဘယ် Images တွေ Process လုပ်လဲ&quot;">​</a></h2><p>Auto tagging က image files တွေကိုအဓိက process လုပ်ပါတယ်။</p><p>tags, orientation, rating, width, height ပြည့်စုံပြီးသား images တွေကို skip လုပ်ပါတယ်။ unnecessary Space calls မဖြစ်စေဖို့ပါ။</p><p>ဖြစ်နိုင်ရင် ImgBed က missing information ကိုပဲဖြည့်ပါတယ်။ ဥပမာ orientation ပဲမရှိလျှင် full content tag flow မခေါ်ဘဲ orientation ထည့်ဖို့ကြိုးစားပါတယ်။</p><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="ကိုယ်ပိုင်-space-ကိုဘာကြောင့်-duplicate-လုပ်သင့်လဲ" tabindex="-1">ကိုယ်ပိုင် Space ကိုဘာကြောင့် Duplicate လုပ်သင့်လဲ? <a class="header-anchor" href="#ကိုယ်ပိုင်-space-ကိုဘာကြောင့်-duplicate-လုပ်သင့်လဲ" aria-label="Permalink to &quot;ကိုယ်ပိုင် Space ကိုဘာကြောင့် Duplicate လုပ်သင့်လဲ?&quot;">​</a></h3><p>Public Spaces တွေကို users အများကြီး share သုံးပါတယ်။ ကိုယ်ပိုင် duplicated Space က အဓိကအားဖြင့် သင့် ImgBed site ပဲသုံးတာကြောင့် ပိုမြန်ပြီးပိုယုံကြည်စိတ်ချရပါတယ်။</p><h3 id="space-က-starting-up-အဖြစ်ဆက်ပြနေတယ်" tabindex="-1">Space က Starting Up အဖြစ်ဆက်ပြနေတယ် <a class="header-anchor" href="#space-က-starting-up-အဖြစ်ဆက်ပြနေတယ်" aria-label="Permalink to &quot;Space က Starting Up အဖြစ်ဆက်ပြနေတယ်&quot;">​</a></h3><p>ပထမဆုံးဖန်တီးပြီးနောက် သို့မဟုတ် idle ကြာပြီးနောက် Space start ဖြစ်ဖို့အချိန်ယူနိုင်ပါတယ်။</p><p>အရင်ဆုံး Space page ကိုဖွင့်ပါ။ image ကိုပုံမှန် recognize လုပ်နိုင်ပြီဆိုရင် ImgBed ကိုပြန်သွားပြီး tagging စပါ။</p><h3 id="space-url-ဘယ်လို-copy-လုပ်မလဲ" tabindex="-1">Space URL ဘယ်လို Copy လုပ်မလဲ? <a class="header-anchor" href="#space-url-ဘယ်လို-copy-လုပ်မလဲ" aria-label="Permalink to &quot;Space URL ဘယ်လို Copy လုပ်မလဲ?&quot;">​</a></h3><p>သင့် Hugging Face Space page ကိုဖွင့်ပြီး browser address ကို copy လုပ်ပါ။</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://huggingface.co/spaces/lintonxue00/wd-tagger</span></span>
<span class="line"><span>https://huggingface.co/spaces/SmilingWolf/wd-tagger</span></span></code></pre></div><h3 id="spaces-အများကြီးထည့်လို့ရလား" tabindex="-1">Spaces အများကြီးထည့်လို့ရလား? <a class="header-anchor" href="#spaces-အများကြီးထည့်လို့ရလား" aria-label="Permalink to &quot;Spaces အများကြီးထည့်လို့ရလား?&quot;">​</a></h3><p>ရပါတယ်။ line တစ်ကြောင်းမှာ Space URL တစ်ခုစီထည့်ပါ။</p><p>Spaces အများကြီးက images တွေကိုအတူ process လုပ်ပြီး images များတဲ့အခါအသုံးဝင်ပါတယ်။</p><h3 id="tags-တွေ-english-ဖြစ်တာဘာကြောင့်လဲ" tabindex="-1">Tags တွေ English ဖြစ်တာဘာကြောင့်လဲ? <a class="header-anchor" href="#tags-တွေ-english-ဖြစ်တာဘာကြောင့်လဲ" aria-label="Permalink to &quot;Tags တွေ English ဖြစ်တာဘာကြောင့်လဲ?&quot;">​</a></h3><p>SmilingWolf models တွေက English tags output ပေးတာဖြစ်ပါတယ်။ ဒါက expected ဖြစ်ပါတယ်။</p><p>tags တွေကို search, filtering, random image API, public gallery filters အတွက်အဓိကသုံးပါတယ်။</p><h3 id="rating-tags-ကိုဘာအတွက်သုံးလဲ" tabindex="-1">Rating Tags ကိုဘာအတွက်သုံးလဲ? <a class="header-anchor" href="#rating-tags-ကိုဘာအတွက်သုံးလဲ" aria-label="Permalink to &quot;Rating Tags ကိုဘာအတွက်သုံးလဲ?&quot;">​</a></h3><p>rating results တွေက Security Settings ထဲက access mode နဲ့အတူအလုပ်လုပ်ပါတယ်။</p><p>ဥပမာ visitor access ကို age rating အလိုက်ကန့်သတ်ထားရင် public browsing နဲ့ random image features တွေက အဲဒီ rules အတိုင်း images တွေကို filter လုပ်ပါတယ်။</p><h2 id="quick-flow" tabindex="-1">Quick Flow <a class="header-anchor" href="#quick-flow" aria-label="Permalink to &quot;Quick Flow&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Hugging Face ထဲ sign in ဝင်ပါ</span></span>
<span class="line"><span>-&gt; SmilingWolf/wd-tagger ဖွင့်ပါ</span></span>
<span class="line"><span>-&gt; Duplicate this Space</span></span>
<span class="line"><span>-&gt; Space build ပြီးအောင်စောင့်ပါ</span></span>
<span class="line"><span>-&gt; သင့် Space URL copy လုပ်ပါ</span></span>
<span class="line"><span>-&gt; ImgBed ထဲ Space URLs ဖြည့်ပါ</span></span>
<span class="line"><span>-&gt; model နဲ့ thresholds ရွေးပါ</span></span>
<span class="line"><span>-&gt; Start tagging သို့မဟုတ် auto-tag on upload enable လုပ်ပါ</span></span></code></pre></div>`,61)])])}const b=e(n,[["render",d]]);export{m as __pageData,b as default};
